#include <stdio.h>
#include <stdbool.h>

#define MAX_N 1000

int main(){
    bool isPrime[MAX_N+1];
    for(int i=0;i<=MAX_N;++i) isPrime[i]=true;
    isPrime[0]=isPrime[1]=false;
    for(int p=2;p*p<=MAX_N;++p){
        if(isPrime[p]){
            for(int mult=p*p; mult<=MAX_N; mult+=p) isPrime[mult]=false;
        }
    }
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int L,R; scanf("%d %d",&L,&R);
        int first=1;
        for(int i=L;i<=R;++i){
            if(isPrime[i]){
                if(!first) printf(" ");
                printf("%d",i);
                first=0;
            }
        }
        printf("\n");
    }
    return 0;
}

